import asyncio
import websockets
from collections import defaultdict

inventory = defaultdict(list)
lock = asyncio.Lock()

class Item:
    def __init__(self, name):
        self.name = name

items = [Item(f"Item{i}") for i in range(10)]
for index, item in enumerate(items):
    player_id = f'player{index % 2 + 1}'
    inventory[player_id].append(item)

async def handle_trade(websocket, path):
    async for message in websocket:
        request = message.split()
        action = request[0]
        
        if action == "trade":
            from_player = request[1]
            to_player = request[2]
            item_name = request[3]

            async with lock:
                from_inventory = inventory[from_player]
                to_inventory = inventory[to_player]

                item_to_trade = next((item for item in from_inventory if item.name == item_name), None)
                if item_to_trade:
                    from_inventory.remove(item_to_trade)
                    to_inventory.append(item_to_trade)

                    response = f"Trade successful: {item_name} from {from_player} to {to_player}"
                else:
                    response = f"Error: {from_player} doesn't have {item_name}"

            await websocket.send(response)

async def main():
    async with websockets.serve(handle_trade, "localhost", 12345):
        await asyncio.Future()

asyncio.run(main())